/**
 * MedX aside layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Secondary aside column for filters.
 */
const ASIDE_TOKENS = Object.freeze({
  primary: { value: "layout-aside-primary", scope: "layout" },
  secondary: { value: "layout-aside-secondary", scope: "layout" },
  muted: { value: "layout-aside-muted", scope: "layout" },
  accent: { value: "layout-aside-accent", scope: "layout" },
  surface: { value: "layout-aside-surface", scope: "layout" },
});

const ASIDE_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const ASIDE_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const asideRegistry = new Map();
const ASIDE_listeners = new Set();
let ASIDE_seq = 0;

function createAsideId(prefix = "medx-layout-aside") {
  ASIDE_seq += 1;
  return `${prefix}-${ASIDE_seq}`;
}

function registerAside(config = {}) {
  const entryId = config.id ?? createAsideId();
  const preset = ASIDE_PRESETS[config.preset ?? "default"] ?? ASIDE_PRESETS.default;
  const token = ASIDE_TOKENS[config.token ?? preset.token] ?? ASIDE_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: ASIDE_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  asideRegistry.set(entryId, entry);
  notifyAsideListeners("register", entry);
  return entry;
}

function updateAside(id, patch = {}) {
  const entry = asideRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyAsideListeners("update", entry);
  return entry;
}

function resolveAside(id) {
  const entry = asideRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listAsideEntries(filter = {}) {
  let items = Array.from(asideRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onAsideEvent(listener) {
  ASIDE_listeners.add(listener);
  return () => ASIDE_listeners.delete(listener);
}

function notifyAsideListeners(type, entry) {
  for (const listener of ASIDE_listeners) {
    try {
      listener({ type, entry, registrySize: asideRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:aside] listener error", err.message);
    }
  }
}

function getAsideMetrics() {
  const items = listAsideEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(ASIDE_TOKENS).length,
    presets: Object.keys(ASIDE_PRESETS).length,
  };
}

async function runMedxAside() {
  console.log("[medx:ui:layout:aside] runtime initialized");
  console.log(`[medx:ui:layout:aside] tokens=${Object.keys(ASIDE_TOKENS).length} presets=${Object.keys(ASIDE_PRESETS).length}`);

  const events = [];
  onAsideEvent((e) => events.push(e.type));

  const domains = Object.keys(ASIDE_SUPPLY_CHAIN);
  const presets = Object.keys(ASIDE_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerAside({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/aside" },
    });
  }

  const first = listAsideEntries()[0];
  if (first) updateAside(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getAsideMetrics();
  const resolved = first ? resolveAside(first.id) : null;

  console.log(`[medx:ui:layout:aside] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:aside] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:aside] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:aside] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:aside] bootstrap complete");
}

module.exports = runMedxAside;
